-- 0001_baseline.up.sql
-- SSA IR DB schema baseline (version 1).
--
-- This file is the frozen DDL source of truth for the SSA IR DB. It is
-- generated by running GORM AutoMigrate + ApplyPatches (the current
-- code-is-schema path in common/consts/ssa.go) against a fresh Postgres 16
-- database, then dumping the schema with:
--   pg_dump --schema-only --no-owner --no-privileges --no-comments
-- The PG16 \restrict/\unrestrict pseudo-commands and version-specific
-- comment lines are stripped so the checksum is stable across machines.
--
-- Cross-checked by common/yak/ssa/ssadb/irschema/drift_test.go, which
-- compares a DB built from this SQL against a DB built from GORM
-- AutoMigrate. Any GORM struct change MUST be accompanied by a new
-- NNNN_*.up.sql migration file + a CurrentIRSchemaVersion bump, or the
-- drift test fails in CI.
--
-- Do NOT hand-edit this file. To regenerate after an intentional schema
-- change, add a new 0002_*.up.sql instead (additive DDL only).

SET statement_timeout = 0;
SET lock_timeout = 0;
SET idle_in_transaction_session_timeout = 0;
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SET check_function_bodies = false;
SET xmloption = content;
SET client_min_messages = warning;
SET row_security = off;

SET default_tablespace = '';

SET default_table_access_method = heap;

